INSERT INTO shell_memory_archives (archive_id, shell_id, session_id, date, full_narrative, started_at, ended_at, harness, provider, model, sprint_ref) VALUES (3, 2, '0001', '2026-06-05', '# 0001 | 2026-06-05 | session opened

## Narrative

